UPDATE ai_prompt_settings
SET prompt_text = replace(
  prompt_text,
  E'Общее резюме\n\n<!-- anchor:summary_start -->\n\n// БЛОК 1: ОБЩАЯ КАРТИНА //',
  E'Общее резюме\n\n// БЛОК 0: ВСТУПЛЕНИЕ //\n\nЗаголовок — plain text, отдельная строка:\n\nКак читать этот отчёт\n\n<!-- anchor:intro_start -->\n\nОдин абзац, 4-6 предложений, без чисел и без цифр биомаркеров. Обращение на «вы». Задачи абзаца:\n— обозначить, что отчёт разбирает все исследованные системы организма и показывает полную картину состояния здоровья;\n— пояснить, что показатели в отчёте сверяются с превентивными референсами, которые строже стандартных лабораторных норм — поэтому отклонение от оптимума не равно проблеме и не повод для тревоги или немедленных действий;\n— пояснить, что часть показателей в допустимом диапазоне не требует коррекции, если в динамике они не будут расти или снижаться дальше;\n— сообщить, что после прочтения отчёта предусмотрен созвон с врачом, который разберёт результаты, ответит на вопросы и объяснит непонятные моменты;\n— упомянуть, что при чтении отчёта можно пользоваться ИИ-ассистентом, если какой-то термин или формулировка непонятны.\n\nТон — спокойный, ровный, слегка тёплый, без медицинского жаргона в этом конкретном абзаце. Никаких метафор, но допустима более человеческая, "разговорная" интонация, чем в остальных блоках отчёта. Не использовать формулировки «отчёт составлен нейросетью/алгоритмом/ИИ» применительно к самому отчёту — про ИИ-ассистента можно упомянуть только как инструмент помощи при чтении.\n\nПоследнее предложение блока — короткий переход к следующему разделу (например: «Перейдём к результатам.» или «Начнём с общей картины вашего состояния.») — без канцелярита и без повторения слова «отчёт».\n\nПример правильного вступления:\n«Этот отчёт разбирает все исследованные системы организма и даёт полную картину вашего текущего состояния. Показатели сверяются с превентивными референсами, которые заметно строже стандартных лабораторных норм, поэтому отклонение от оптимума само по себе не повод для беспокойства или немедленных действий — часть значений допустима в текущем диапазоне, если в дальнейшем не будет нарастать. После знакомства с отчётом предусмотрен видеозвонок с врачом, который разберёт результаты подробно и ответит на все вопросы, а если по ходу чтения какой-то термин покажется непонятным — можно обратиться к ИИ-ассистенту. Теперь перейдём к результатам.»\n\n<!-- anchor:intro_end -->\n\n<!-- anchor:summary_start -->\n\n// БЛОК 1: ОБЩАЯ КАРТИНА //'
),
updated_at = now()
WHERE key = 'summary_system';